<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">curl.exe</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">H </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Authorization: Bearer YOUR_API_KEY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> \`</span></span>
